## 解説

各要素を見て `x % 2 == 0` のものだけ出力します。`first` フラグで値の間にだけ空白を入れます（偶数が無いときは空行になります）。

```cpp
bool first = true;
for (int x : v) if (x % 2 == 0) {
    if (!first) cout << " ";
    cout << x;
    first = false;
}
cout << "\n";
```

answer_code:
#include <bits/stdc++.h>
using namespace std;

int main() {
    int n;
    cin >> n;
    vector<int> v(n);
    for (int i = 0; i < n; i++) cin >> v[i];
    bool first = true;
    for (int x : v) if (x % 2 == 0) {
        if (!first) cout << " ";
        cout << x;
        first = false;
    }
    cout << "\n";
    return 0;
}
